1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Empty / processing fee ---
6	  it("empty item list returns premium 5 G (processing fee only)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums per item ---
15	  it.todo("single plain sword returns premium 105 G (100 base + 5 fee)");
16	  it.todo("single plain amulet returns premium 65 G (60 base + 5 fee)");
17	  it.todo("single plain staff returns premium 85 G (80 base + 5 fee)");
18	  it.todo("single plain potion returns premium 45 G (40 base + 5 fee)");
19	
20	  // --- Components ---
21	  it.todo("single rune returns premium 30 G (25 base + 5 fee)");
22	  it.todo("2 runes returns premium 55 G (50 base + 5 fee)");
23	  it.todo("3 runes returns premium 65 G (block: 60 base + 5 fee)");
24	  it.todo("4 runes returns premium 105 G (no block: 100 base + 5 fee)");
25	  it.todo("7 runes returns premium 180 G (175 base + 5 fee)");
26	
27	  // --- 'Alike' clarification (❓) ---
28	  it.todo("2 runes + 1 moonstone returns premium 80 G (75 base + 5 fee — different types, no block)");
29	  it.todo("3 runes + 3 moonstones returns premium 125 G (120 base + 5 fee — two separate blocks)");
30	
31	  // --- Cursed surcharge ---
32	  it.todo("single cursed sword (newcomer) returns 165 G (100 base + 50 curse + 10 first + 5 fee)");
33	
34	  // --- High enchantment threshold ---
35	  it.todo("sword with enchantment 5 (newcomer) adds 30% high-enchantment surcharge → 145 G (100 + 30 + 10 + 5)");
36	  it.todo("sword with enchantment 4 (newcomer) does not add high-enchantment surcharge → 115 G (100 + 10 + 5)");
37	
38	  // --- Modifier scope on multi-item policies (❓) ---
39	  it.todo("policy with cursed sword + plain amulet (newcomer) → 231 G (160 base + 50 curse + 16 first + 5 fee)");
40	
41	  // --- Loyalty (≥ 2 years) ---
42	  it.todo("plain sword for 2-year customer → loyalty applies; first contract → 95 G (100 − 20 + 10 + 5)");
43	
44	  // --- Follow-up contract ---
45	  it.todo("second quote for newcomer (0 years) of plain sword → follow-up discount applies → 100 G (100 − 15 + 10 + 5)");
46	
47	  // --- Rounding in MHPCO favor (premium rounds up) ---
48	  it.todo("premium calculation yielding 197.5 G rounds up to 198 G");
49	
50	  // --- Integration: long-standing 2nd contract ---
51	  it.todo("long-standing customer's 2nd contract with cursed sword enchantment 7 → 160 G");
52	
53	  // --- Claim: standard reimbursement ---
54	  it.todo("standard sword damage 500 G → payout 400 G (500 − 100 deductible)");
55	  it.todo("rune damage 200 G → payout 100 G (200 − 100 deductible; no special clause)");
56	
57	  // --- Claim: high enchantment ---
58	  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
59	
60	  // --- Claim: dragon material ---
61	  it.todo("dragon sword enchantment 5, damage 800 G → payout 700 G (full then deductible)");
62	
63	  // --- Claim: both clauses (high enchantment wins) ---
64	  it.todo("dragon sword enchantment 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
65	  it.todo("dragon sword enchantment exactly 8, damage 1000 G → payout 400 G (high-enchantment clause applies)");
66	
67	  // --- Multiple damages: deductible per event ---
68	  it.todo("dragon attack on sword (500) and amulet (300) → payout 600 G (deductible per item)");
69	
70	  // --- Multiple same-type items ---
71	  it.todo("policy with two swords, both damaged → each gets own deductible");
72	  it.todo("damages array has more items of a type than policy covers → CLI exits non-zero (claim rejected)");
73	
74	  // --- Cap ---
75	  it.todo("sword (cap 2000) with two 1500 G claims → first payout 1400, remaining 600; second payout 600, remaining 0");
76	  it.todo("cursed sword cap based on unmodified insurance value → 2000 G");
77	
78	  // --- Rounding payout (rounds down) ---
